import React, { useState, useEffect, useRef } from 'react';
import { Ruler, Palette, Camera, Trash2, Save, CheckCircle, ShieldCheck } from 'lucide-react';
import './styles/ProfileSection.css';

const ProfileSection = () => {
  const [formData, setFormData] = useState({
    name: '', 
    gender: '',
    height: '', 
    weight: '', 
    skinTone: '',
    chest: '', 
    waist: 0, 
    hips: 0, 
    fullBodyImage: ''
  });
  
  const [loading, setLoading] = useState(true);
  const [status, setStatus] = useState({ text: '', type: '' });
  const fileInputRef = useRef(null);

  useEffect(() => {
    fetchProfile();
  }, []);

  const fetchProfile = async () => {
    try {
      const token = localStorage.getItem('token');
      // Using a direct fetch with robust error handling
      const res = await fetch('http://localhost:5000/api/profile', {
        method: 'GET',
        headers: { 
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json' 
        }
      });
      
      const data = await res.json();
      console.log("SUCCESS: Received Profile Data:", data); 
      
      if (res.ok) {
        // We use a functional update to ensure we don't lose existing state
        setFormData({
          name: data.name || '',
          gender: data.gender || '',
          height: data.height || '',
          weight: data.weight || '',
          skinTone: data.skinTone || '',
          chest: data.chest || '',
          // Logic to catch data whether nested or top-level
          
          waist: data.waist || data.bodyMeasurements?.waist || 0,
          hips: data.hips || data.bodyMeasurements?.hips || 0,
          fullBodyImage: data.fullBodyImage || ''
        });
      } else {
        console.error("Auth Failure or Server Error:", data.message);
      }
    } catch (error) {
      console.error("Network error fetching profile:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleImageUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onloadend = () => {
      setFormData({ ...formData, fullBodyImage: reader.result });
    };
    reader.readAsDataURL(file);
  };

  const handleSave = async () => {
    try {
      const token = localStorage.getItem('token');
      setStatus({ text: 'Syncing...', type: 'info' });

      const res = await fetch('http://localhost:5000/api/profile/update', {
        method: 'PUT',
        headers: { 
          'Content-Type': 'application/json', 
          'Authorization': `Bearer ${token}` 
        },
        body: JSON.stringify(formData)
      });
      
      if (res.ok) {
        setStatus({ text: 'Neural Profile Synchronized!', type: 'success' });
        setTimeout(() => setStatus({ text: '', type: '' }), 3000);
      } else {
        throw new Error("Update failed");
      }
    } catch (error) {
      setStatus({ text: 'Update Failed. Check connection.', type: 'error' });
      setTimeout(() => setStatus({ text: '', type: '' }), 3000);
    }
  };

  if (loading) return (
    <div className="dash-loader">
      <div className="spinner"></div>
      <p>Fetching Neural Biometrics...</p>
    </div>
  );

  return (
    <div className="profile-container animate-in">
      <header className="profile-header">
        <div className="title-area">
          <h1>Neural <span className="text-gradient">Fit Profile</span></h1>
          <p>Your digital silhouette is synced and ready for AI Try-On.</p>
        </div>
        <button className="save-btn" onClick={handleSave}>
          <Save size={18} /> Update Profile
        </button>
      </header>

      {status.text && <div className={`status-msg ${status.type}`}>{status.text}</div>}

      <div className="profile-grid">
        {/* LEFT: PHOTO SECTION */}
        <div className="profile-card photo-card">
          <div className="card-label"><Camera size={16} /> Virtual Model Photo</div>
          <div className="full-body-preview">
            {formData.fullBodyImage ? (
              <>
                <img src={formData.fullBodyImage} alt="Neural Model" />
                <button 
                  className="delete-photo-btn" 
                  onClick={() => setFormData({...formData, fullBodyImage: ''})}
                >
                  <Trash2 size={18} />
                </button>
              </>
            ) : (
              <div className="upload-placeholder" onClick={() => fileInputRef.current.click()}>
                <Camera size={40} />
                <span>Upload Full-Body Photo</span>
                <p>Ensure good lighting for 3D generation</p>
              </div>
            )}
            <input 
              type="file" 
              hidden 
              ref={fileInputRef} 
              onChange={handleImageUpload} 
              accept="image/*" 
            />
          </div>
          <div className="privacy-hint">
            <ShieldCheck size={14} /> Biometric data is encrypted
          </div>
        </div>

        {/* RIGHT: DATA SECTION */}
        <div className="profile-card data-card">
          <div className="card-label"><Ruler size={16} /> Live Biometrics</div>
          
          <div className="input-row">
            <div className="input-group">
              <label>Full Name</label>
              <input 
                type="text" 
                name="name" 
                value={formData.name || ''} 
                onChange={handleInputChange} 
              />
            </div>
           <div className="input-group">
  <label>Gender</label>
  <select 
    name="gender" 
    value={formData.gender} // This binds the value to the "female" string from DB
    onChange={handleInputChange} 
    className="profile-select"
  >
    <option value="">Select Gender</option>
    <option value="male">Male</option>
    <option value="female">Female</option>
    <option value="other">Other</option>
  </select>
</div>
            <div className="input-group">
              <label>Skin Tone</label>
              <input 
                type="text" 
                name="skinTone" 
                value={formData.skinTone || ''} 
                onChange={handleInputChange} 
              />
            </div>
          </div>

          <div className="measure-grid">
            <div className="measure-item">
              <label>Height (cm)</label>
              <input 
                type="number" 
                name="height" 
                value={formData.height || ''} 
                onChange={handleInputChange} 
              />
            </div>
            <div className="measure-item">
              <label>Weight (kg)</label>
              <input 
                type="number" 
                name="weight" 
                value={formData.weight || ''} 
                onChange={handleInputChange} 
              />
            </div>
            <div className="measure-item highlight-pink">
              <label>Chest (inch)</label>
              <input 
                type="number" 
                name="chest" 
                value={formData.chest || ''} 
                onChange={handleInputChange} 
              />
            </div>
            <div className="measure-item highlight-pink">
              <label>Waist (inch)</label>
              <input 
                type="number" 
                name="waist" 
                value={formData.waist || 0} 
                onChange={handleInputChange} 
              />
            </div>
            <div className="measure-item highlight-pink">
              <label>Hips (inch)</label>
              <input 
                type="number" 
                name="hips" 
                value={formData.hips || 0} 
                onChange={handleInputChange} 
              />
            </div>
          </div>

          <div className="ai-status-box">
             <CheckCircle size={20} className="glow-icon" />
             <div>
                <h4>Biometric Sync Active</h4>
                <p>Edit any value above to update your virtual model.</p>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProfileSection;
